// =============================================================================
// SCORING UTILITIES
// =============================================================================

interface TestResult {
  category: 'intent' | 'synonym' | 'format' | 'language';
  passed: boolean;
  input: string;
  expected: string;
  actual: string;
}

interface ScoreReport {
  total: number;
  byCategory: {
    intent: { passed: number; total: number; score: number };
    synonym: { passed: number; total: number; score: number };
    format: { passed: number; total: number; score: number };
    language: { passed: number; total: number; score: number };
  };
  failures: TestResult[];
}

const WEIGHTS = {
  intent: 0.4,
  synonym: 0.3,
  format: 0.2,
  language: 0.1
};

export function calculateScore(results: TestResult[]): ScoreReport {
  const byCategory = {
    intent: { passed: 0, total: 0, score: 0 },
    synonym: { passed: 0, total: 0, score: 0 },
    format: { passed: 0, total: 0, score: 0 },
    language: { passed: 0, total: 0, score: 0 }
  };

  const failures: TestResult[] = [];

  for (const result of results) {
    byCategory[result.category].total++;
    if (result.passed) {
      byCategory[result.category].passed++;
    } else {
      failures.push(result);
    }
  }

  // Calculate category scores (0-100)
  for (const category of Object.keys(byCategory) as Array<keyof typeof byCategory>) {
    const { passed, total } = byCategory[category];
    byCategory[category].score = total > 0 ? (passed / total) * 100 : 100;
  }

  // Calculate weighted total
  const total =
    byCategory.intent.score * WEIGHTS.intent +
    byCategory.synonym.score * WEIGHTS.synonym +
    byCategory.format.score * WEIGHTS.format +
    byCategory.language.score * WEIGHTS.language;

  return { total, byCategory, failures };
}

